mapper.select:
select p.out_put_id as outPutId, p.ent_code as entCode, e.ent_name as entName, p.out_put_code as outPutCode, p.out_put_name as outPutName, p.out_put_type as outPutType, p.mn_num as mnNum, p.out_put_status as outPutStatus, p.longitude, p.latitude, p.out_put_height as outPutHeight, p.out_put_position as outPutPosition, p.install_online as installOnline from t_ent_out_put_info p left join t_bas_enterprise e on e.ent_code = p.ent_code
and e.ent_code in
#{entCode}

select p.ent_code, e.ent_name, e.shorter_name, p.out_put_type, p.out_put_id, p.out_put_code, p.out_put_name from t_ent_out_put_info p left join t_bas_enterprise e on e.ent_code = p.ent_code
and p.ent_code in
#{entCode}
and p.out_put_type in
#{outPutType}

select out_put_id as outPutId, out_put_code as outPutCode, out_put_name as outPutName, out_put_type as outPutType, out_put_status as outPutStatus, mn_num as mnNum
from t_ent_out_put_info
where ent_code = #{entCode}

    and out_put_type = #{outPutType}

order by create_time desc

select i.out_put_id, e.ent_code, e.ent_name, i.out_put_code, i.out_put_name, i.out_put_type, i.out_put_status, i.longitude, i.latitude, i.clock_range, i.out_put_height, i.out_put_position, i.install_online, i.mn_num, i.trans_rate, i.valid_rate, i.real_data_interval, i.minute_data_interval, i.pollutant_code, i.remark, i.create_time, i.update_time from t_ent_out_put_info i left join t_bas_enterprise e on e.ent_code = i.ent_code
and i.ent_code = #{entCode}
and i.ent_code in
#{entCode}
and e.ent_name like concat('%', #{entName}, '%') and i.out_put_name like concat('%', #{outPutName}, '%') and i.out_put_type = #{outPutType} and i.out_put_status = #{outPutStatus} and i.mn_num like concat('%', #{mnNum}, '%')
order by i.out_put_id desc

mapper.update:
update t_ent_out_put_info
out_put_code = #{outPutCode}, out_put_name = #{outPutName}, out_put_type = #{outPutType}, out_put_status = #{outPutStatus}, longitude = #{longitude}, latitude = #{latitude}, clock_range = #{clockRange}, out_put_height = #{outPutHeight}, out_put_position = #{outPutPosition}, install_online = #{installOnline}, mn_num = #{mnNum}, trans_rate = #{transRate}, valid_rate = #{validRate}, real_data_interval = #{realDataInterval}, minute_data_interval = #{minuteDataInterval}, pollutant_code = #{pollutantCode}, control_level = #{controlLevel}, per_id = #{perId}, per_alarm_id = #{perAlarmId}, remark = #{remark}, update_time = #{updateTime},
where out_put_id = #{outPutId}

mapper.select:
select out_put_id as outPutId, count(id) as `count` from t_bas_user_put_info
where user_id = #{userId}
group by out_put_id

select u.out_put_id as outPutId, p.ent_code as entCode, p.out_put_code as outPutCode, p.out_put_type as outPutType
from t_bas_user_put_info u left join t_ent_out_put_info p on p.out_put_id = u.out_put_id
where u.user_id = #{userId}

select out_put_id as outPutId, out_put_status as outPutStatus from t_ent_out_put_info
and ent_code in
#{entCode}
